import{_ as i,o as a,c as s,a2 as t}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Suivi & Reporting","description":"","frontmatter":{"title":"Suivi & Reporting"},"headers":[],"relativePath":"docs/fr/publishers/sponsored-mail/reporting.md","filePath":"docs/fr/publishers/sponsored-mail/reporting.md"}'),r={name:"docs/fr/publishers/sponsored-mail/reporting.md"};function l(o,e,n,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="suivi-des-volumes-reporting" tabindex="-1">Suivi des Volumes (Reporting) <a class="header-anchor" href="#suivi-des-volumes-reporting" aria-label="Permalink to &quot;Suivi des Volumes (Reporting)&quot;">​</a></h1><p>Le reporting hebdomadaire est obligatoire pour assurer le suivi des stocks et <strong>déclencher votre facturation</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Obligation hebdomadaire — Lundi ou Mardi</p><p>Chaque début de semaine, déclarez le volume exact d&#39;asiles distribués la semaine précédente. Cette déclaration conditionne directement votre paiement.</p></div><hr><h2 id="comment-declarer-les-volumes" tabindex="-1">Comment déclarer les volumes ? <a class="header-anchor" href="#comment-declarer-les-volumes" aria-label="Permalink to &quot;Comment déclarer les volumes ?&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Se connecter à la plateforme</h3><p>Rendez-vous sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Accéder à la campagne</h3><p>Allez dans <strong>&quot;Mes Campagnes&quot;</strong> et sélectionnez la campagne active.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Ouvrir le suivi</h3><p>Ouvrez l&#39;onglet <strong>&quot;Configuration et suivi&quot;</strong>.</p></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Saisir le volume distribué</h3><p>Dans le tableau de suivi, renseignez :</p><ul><li>La période (ex : Semaine 42)</li><li>La quantité insérée</li></ul></div></div><hr><h2 id="cloturer-une-campagne" tabindex="-1">Clôturer une campagne <a class="header-anchor" href="#cloturer-une-campagne" aria-label="Permalink to &quot;Clôturer une campagne&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📦 Cas A — Stock Épuisé</strong><p>Vous avez distribué l&#39;intégralité des supports reçus. La campagne s&#39;arrête naturellement.</p></div><div class="gi-value-card"><strong>🏁 Cas B — Objectif Atteint (Capped)</strong><p>Le volume commandé est atteint. Clôturez la campagne même s&#39;il reste du stock, sauf instruction contraire pour écouler le reliquat.</p></div></div><p>Une fois la campagne terminée, cliquez sur <strong>&quot;Clôturer la campagne&quot;</strong> pour valider la prestation.</p><div class="tip custom-block"><p class="custom-block-title">Déclenchement du paiement</p><p>La clôture de campagne valide la prestation et déclenche le crédit de votre revenu sur le Wallet — disponible 30 jours après la fin de campagne.</p></div>',14)])])}const v=i(r,[["render",l]]);export{m as __pageData,v as default};
